  trc.test_run_id,
  json_extract(value, '$.method'),
  json_extract(value, '$.url'),
  json_extract(value, '$.url'),
  json_extract(value, '$.status'),
  json_extract(value, '$.duration'),
  json_extract(value, '$.resourceType'),
